qry:select.qry:xquery:
for $r in sql(' select o.c_centro_costo, o.d_centro_costo from ORG08_CS_COSTO as o, liq97_personal_emp as l JOIN o.c_centro_costo INNER l.c_centro_costo_ult
{%? (#PARAMIN:@oi_centro_costo!='') {% WHERE o.oi_centro_costo = {%=#PARAMIN:@oi_centro_costo%} %} {% %} %}
group by o.c_centro_costo, o.d_centro_costo order by c_centro_costo ASC ')/ROWS/ROW

for $r in sql(' SELECT LIQ12_TIPOS_CONC.C_TIPO_CONCEPTO, LIQ12_TIPOS_CONC.d_tipo_concepto, LIQ12_TIPOS_CONC.E_ORDEN FROM LIQ12_TIPOS_CONC WHERE
{%? (#PARAMIN:@oi_tipo_concepto!='') {% LIQ12_TIPOS_CONC.oi_tipo_concepto = {%=#PARAMIN:@oi_tipo_concepto%} %} {% LIQ12_TIPOS_CONC.l_nolistado != 1 %} %}
ORDER BY E_ORDEN ASC, C_TIPO_CONCEPTO ASC')/ROWS/ROW

for $r in sql(' SELECT LIQ96_CONCEPTOS.c_concepto, LIQ96_CONCEPTOS.d_concepto
FROM LIQ99_RECIBOS, LIQ20_CONC_LIQ_PER, LIQ96_CONCEPTOS, LIQ19_EJECUCIONES, LIQ19_LIQUIDACION
{%? (#PARAMIN:@ccosto=1 ) {% , LIQ20_TOT_LIQ_PER , LIQ97_PERSONAL_EMP %} {% %} %} {%? (#PARAMIN:@ORGA=1 ) {% , LIQ20_TOT_LIQ_PER , LIQ97_PERSONAL_EMP, PER02_PERSONAL_EMP, ORG02_ESTRUC_PERS , ORG03_EMPRESAS %} {% %} %}
JOIN LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per, LIQ99_RECIBOS.oi_liquidacion_ddo INNER LIQ19_EJECUCIONES.oi_liquidacion_ddo, LIQ19_LIQUIDACION.oi_liquidacion INNER LIQ19_EJECUCIONES.oi_liquidacion,
LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo
{%? (#PARAMIN:@ccosto=1) {% , LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ99_RECIBOS.oi_tot_liq_per, LIQ97_PERSONAL_EMP.oi_per_emp_ddo INNER LIQ20_TOT_LIQ_PER.oi_per_emp_ddo %} {% %} %} {%? (#PARAMIN:@orga=1) {% , LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ99_RECIBOS.oi_tot_liq_per, LIQ97_PERSONAL_EMP.oi_per_emp_ddo INNER LIQ20_TOT_LIQ_PER.oi_per_emp_ddo, ORG02_ESTRUC_PERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, LIQ97_PERSONAL_EMP.E_NUMERO_LEGAJO INNER PER02_PERSONAL_EMP.E_NUMERO_LEGAJO, ORG03_EMPRESAS.oi_empresa INNER PER02_PERSONAL_EMP.oi_empresa, ORG03_EMPRESAS.c_empresa INNER LIQ97_PERSONAL_EMP.c_empresa %} {% %} %}
WHERE LIQ20_CONC_LIQ_PER.n_valor != \'0.00\' AND LIQ99_RECIBOS.oi_liquidacion_ddo = {#PARAMIN:@oi_liquidacion} AND LIQ96_CONCEPTOS.c_tipo_concepto = {#SOURCE:@c_tipo_concepto}
{%? (#PARAMIN:@ccosto=1) {% and LIQ97_PERSONAL_EMP.c_centro_costo_ult = {#COSTO:@c_centro_costo} %} {% %} %}
{%? (#PARAMIN:@orga=1) {% AND ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%}) AND ORG02_ESTRUC_PERS.oi_estructura = {#ESTRUCTURA:@oi_estructura} %} {% %} %} {%? (#PARAMIN:@l_simulacion!='') {% AND LIQ19_LIQUIDACION.l_simulacion = {%= #PARAMIN:@l_simulacion %} %} {% %} %} GROUP BY LIQ96_CONCEPTOS.c_concepto, LIQ96_CONCEPTOS.d_concepto
')/ROWS/ROW

for $r in sql(' SELECT LIQ97_PERSONAL_EMP.e_numero_legajo, LIQ20_CONC_LIQ_PER.n_valor, LIQ20_CONC_LIQ_PER.n_cantidad, LIQ97_PERSONAL_EMP.c_nro_cuil, LIQ97_PERSONAL_EMP.d_ape_y_nom
FROM LIQ20_TOT_LIQ_PER, LIQ99_RECIBOS, LIQ97_PERSONAL_EMP, LIQ20_CONC_LIQ_PER, LIQ96_CONCEPTOS, LIQ19_EJECUCIONES, LIQ19_LIQUIDACION
{%? (#PARAMIN:@ORGA=1 ) {% , PER02_PERSONAL_EMP, ORG02_ESTRUC_PERS, ORG03_EMPRESAS %} {% %} %}
JOIN LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ99_RECIBOS.oi_tot_liq_per, LIQ20_TOT_LIQ_PER.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo, LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per, LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo, LIQ99_RECIBOS.oi_liquidacion_ddo INNER LIQ19_EJECUCIONES.oi_liquidacion_ddo, LIQ19_LIQUIDACION.oi_liquidacion INNER LIQ19_EJECUCIONES.oi_liquidacion
{%? (#PARAMIN:@orga=1) {% ,ORG02_ESTRUC_PERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, LIQ97_PERSONAL_EMP.E_NUMERO_LEGAJO INNER PER02_PERSONAL_EMP.E_NUMERO_LEGAJO, ORG03_EMPRESAS.oi_empresa INNER PER02_PERSONAL_EMP.oi_empresa, ORG03_EMPRESAS.c_empresa INNER LIQ97_PERSONAL_EMP.c_empresa %} {% %} %}
WHERE LIQ99_RECIBOS.oi_liquidacion_ddo = {#PARAMIN:@oi_liquidacion} AND LIQ96_CONCEPTOS.c_concepto = {#SOURCE:@c_concepto}
{%? (#PARAMIN:@ccosto=1) {% and LIQ97_PERSONAL_EMP.c_centro_costo_ult = {#COSTO:@c_centro_costo} %} {% %} %} {%? (#PARAMIN:@orga=1) {% AND ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%}) AND ORG02_ESTRUC_PERS.oi_estructura = {#ESTRUCTURA:@oi_estructura} %} {% %} %} {%? (#PARAMIN:@l_simulacion!='') {% AND LIQ19_LIQUIDACION.l_simulacion = {%= #PARAMIN:@l_simulacion %} %} {% %} %} ')/ROWS/ROW

for $r in sql(' SELECT ORG02_ESTRUC_PERS.oi_estructura FROM PER02_PERSONAL_EMP, ORG02_ESTRUC_PERS, LIQ99_LIQUIDACION, ORG03_EMPRESAS JOIN ORG02_ESTRUC_PERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, LIQ99_LIQUIDACION.c_empresa INNER ORG03_EMPRESAS.c_empresa , PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa WHERE
LIQ99_LIQUIDACION.oi_liquidacion_ddo = {#PARAMIN:@oi_liquidacion}
GROUP BY ORG02_ESTRUC_PERS.oi_estructura ')/ROWS/ROW
